
@use '../assets/variables.scss' as *;
@use '../assets/markdown.scss' as *;

.lobby {
	display: flex;
	flex-direction: column;
	margin: auto;

	&__header {
		display: flex;
		flex-direction: column;
		align-items: center;
		text-align: center;
	}

	&__countdown,
	&__description {
		margin-top: 25px;
		max-width: $messages-list-max-width;
	}

	:deep(.rich-text--wrapper) {
		text-align: start;
		@include markdown;
	}
}
