

.solid {
	margin: 0;
}

.call-duration-hint {
	display: flex;
	padding: calc(var(--default-grid-baseline) * 2);
}

.call-time {
	display: flex;
	justify-content: center;
	align-items: center;
	height: var(--default-clickable-area);
	font-weight: bold;

	&__text {
		display: flex;
		flex-direction: column;
		align-items: center;
		// Align characters width for any font
		font-variant-numeric: tabular-nums;
	}

	&__placeholder {
		height: 0;
		overflow: hidden;
	}

	&__recording-icon {
		animation: pulse 2s infinite;
		color: var(--color-element-error, var(--color-error));

		&--start {
			color: var(--color-loading-light);
		}
	}
}

:deep(.button-vue) {
	justify-content: left !important;
	color: #fff !important;

	&:disabled {
		opacity: 1 !important;
		pointer-events: none;
	}
}

@keyframes pulse {
	0% {
		opacity: 1;
	}
	50% {
		opacity: 0.7;
	}
	100% {
		opacity: 1;
	}
}

