
.reactions-wrapper {
	--minimal-button-width: 48px;
	--font-family-emoji: 'Segoe UI Emoji', 'Segoe UI Symbol', 'Segoe UI', 'Apple Color Emoji', 'Twemoji Mozilla', 'Noto Color Emoji', 'EmojiOne Color', 'Android Emoji';
	display: contents;

	// Overwrite NcButton styles
	:deep(.button-vue) {
		min-width: var(--minimal-button-width);
	}

	&.light :deep(.button-vue--secondary) {
		background-color: var(--color-primary-element-extra-light);
		&:hover {
			background-color: var(--color-primary-element-extra-light-hover);
		}
	}

	.reaction-emoji {
		font-family: var(--font-family-emoji);
	}

	.reaction-button--trigger {
		height: 100%;
	}

	.reaction-button--thumbnail {
		height: 100%;
		width: var(--minimal-button-width);
		pointer-events: none;
	}
}

.reaction-details {
	padding: 8px;
	max-width: 250px;
}

.details-loading {
	display: flex;
	justify-content: center;
	width: 38px;
}

.more-reactions-button {
	text-decoration: underline;
	&:hover {
		text-decoration: none;
	}
}

// Split view
.reactions-wrapper.compact {
	.reaction-button--trigger,
	.reaction-button--thumbnail {
		padding-inline: 4px;
	}
}
